import tarfile
import os
from pathlib import Path

def extract_tar(tar_path, destination):
    """
    Extract a tar file to a destination directory securely.
    
    Args:
        tar_path (str): Path to the tar file
        destination (str): Destination directory path
    
    Raises:
        ValueError: If paths are invalid or unsafe
        tarfile.TarError: If tar file is invalid
        OSError: If there are file system errors
    """
    # Validate input paths
    if not tar_path or not destination:
        raise ValueError("Both tar path and destination must be provided")
    
    # Resolve absolute paths
    tar_path = os.path.abspath(tar_path)
    destination = os.path.abspath(destination)
    
    # Check if tar file exists and is a file
    if not os.path.isfile(tar_path):
        raise ValueError(f"Tar file does not exist: {tar_path}")
    
    # Create destination directory if it doesn't exist
    os.makedirs(destination, exist_ok=True)
    
    # Validate that destination is within allowed scope (prevent path traversal)
    try:
        # Get the real path of destination to resolve any symbolic links
        real_destination = os.path.realpath(destination)
        # Get the real path of the current working directory
        cwd = os.path.realpath(os.getcwd())
        
        # Ensure destination is within current working directory
        if not real_destination.startswith(cwd):
            raise ValueError("Destination path is outside of allowed scope")
    except OSError:
        raise ValueError("Invalid destination path")
    
    # Open and extract tar file
    try:
        with tarfile.open(tar_path, 'r') as tar:
            # Check for path traversal vulnerabilities
            for member in tar.getmembers():
                if member.path.startswith('/') or '..' in member.path:
                    raise ValueError("Tar file contains invalid paths")
            
            # Extract all members
            tar.extractall(path=destination)
            
    except tarfile.TarError as e:
        raise tarfile.TarError(f"Error extracting tar file: {str(e)}")
    except Exception as e:
        raise OSError(f"Error during extraction: {str(e)}")